import { Check } from "lucide-react"

const ROWS = [
  {
    kicker: "Taste",
    title: "Bold flavor, no aftertaste",
    body: "We dial in every batch on real fruit and a whisper of fizz. It tastes like the label looks — fun.",
    points: ["Pressed fruit base", "Lightly carbonated", "No artificial sweeteners"],
    color: "bg-accent",
  },
  {
    kicker: "Body",
    title: "Light enough to keep up",
    body: "40 calories, no jitters, no crash. The can you reach for at 3pm and again at the beach.",
    points: ["40 calories", "Naturally caffeinated", "Vegan & gluten-free"],
    color: "bg-secondary text-secondary-foreground",
  },
]

/**
 * Retro features — alternating rounded rows with a bright color panel.
 */
export function FeatureRetro() {
  return (
    <section className="bg-background px-5 py-16 text-foreground sm:px-8 sm:py-24">
      <div className="mx-auto max-w-6xl space-y-6">
        {ROWS.map((r, i) => (
          <div
            key={r.title}
            className={`grid items-center gap-6 rounded-[2rem] border-2 border-foreground bg-card p-4 shadow-[5px_5px_0_0_var(--foreground)] md:grid-cols-2 md:p-5 ${
              i % 2 === 1 ? "md:[&>*:first-child]:order-2" : ""
            }`}
          >
            <div className="p-4 sm:p-6">
              <span className="inline-block rounded-full border-2 border-foreground bg-primary px-3 py-1 text-xs font-black text-primary-foreground">
                {r.kicker}
              </span>
              <h3 className="mt-4 text-3xl font-black leading-tight tracking-tight">{r.title}</h3>
              <p className="mt-3 font-medium text-muted-foreground">{r.body}</p>
              <ul className="mt-5 space-y-2">
                {r.points.map((p) => (
                  <li key={p} className="flex items-center gap-2.5 font-bold">
                    <span className="grid size-6 place-items-center rounded-full border-2 border-foreground bg-accent">
                      <Check className="size-3.5" />
                    </span>
                    {p}
                  </li>
                ))}
              </ul>
            </div>
            <div className={`grid min-h-[220px] place-items-center rounded-[1.5rem] border-2 border-foreground ${r.color}`}>
              <span className="text-6xl font-black opacity-80">{String(i + 1).padStart(2, "0")}</span>
            </div>
          </div>
        ))}
      </div>
    </section>
  )
}

"use client"

import { useRef } from "react"
import { motion, useScroll, useTransform } from "framer-motion"

/**
 * Retro parallax — a statement band whose Memphis shapes drift on scroll.
 */
export function ParallaxRetro() {
  const ref = useRef<HTMLDivElement>(null)
  const { scrollYProgress } = useScroll({ target: ref, offset: ["start end", "end start"] })

  const y1 = useTransform(scrollYProgress, [0, 1], ["-30%", "30%"])
  const y2 = useTransform(scrollYProgress, [0, 1], ["20%", "-20%"])
  const rotate = useTransform(scrollYProgress, [0, 1], [0, 45])

  return (
    <section
      ref={ref}
      className="relative grid min-h-[440px] place-items-center overflow-hidden border-y-2 border-foreground bg-primary px-5 py-20 text-primary-foreground"
    >
      <motion.div
        style={{ y: y1 }}
        className="pointer-events-none absolute -left-6 top-10 size-32 rounded-full border-[10px] border-accent"
        aria-hidden
      />
      <motion.div
        style={{ y: y2, rotate }}
        className="pointer-events-none absolute right-[8%] bottom-8 size-24 rounded-2xl bg-secondary"
        aria-hidden
      />
      <motion.div
        style={{ y: y2 }}
        className="pointer-events-none absolute left-[14%] bottom-12 size-6 rounded-full bg-accent"
        aria-hidden
      />

      <div className="relative max-w-3xl text-center">
        <p className="text-sm font-black tracking-[0.25em] uppercase">Since 2019</p>
        <h2 className="mt-4 text-[clamp(2.25rem,7vw,5rem)] font-black leading-[0.95] tracking-tight">
          Loud cans, good vibes, zero compromise.
        </h2>
      </div>
    </section>
  )
}

import { Star } from "lucide-react"

const REVIEWS = [
  { quote: "Tastes like summer in a can. My kids fight over the last one.", name: "Jess M.", color: "bg-accent" },
  { quote: "Finally a soda I don't feel weird about drinking daily.", name: "Andre P.", color: "bg-secondary text-secondary-foreground" },
  { quote: "The mango one is dangerous. I bought four cases.", name: "Lena K.", color: "bg-card" },
  { quote: "Brought it to a party and everyone asked where to buy it.", name: "Sam T.", color: "bg-primary text-primary-foreground" },
]

/**
 * Retro testimonials — bright rounded review cards with star ratings.
 */
export function TestimonialsRetro() {
  return (
    <section className="bg-background px-5 py-16 text-foreground sm:px-8 sm:py-24">
      <div className="mx-auto max-w-6xl">
        <div className="flex flex-wrap items-end justify-between gap-4">
          <h2 className="text-[clamp(2rem,5vw,3.25rem)] font-black tracking-tight">People are fizzing</h2>
          <div className="flex items-center gap-2 rounded-full border-2 border-foreground bg-accent px-4 py-1.5 font-black shadow-[3px_3px_0_0_var(--foreground)]">
            <Star className="size-4 fill-foreground" /> 4.9 · 48k reviews
          </div>
        </div>

        <div className="mt-10 grid gap-5 sm:grid-cols-2 lg:grid-cols-4">
          {REVIEWS.map((r) => (
            <figure
              key={r.name}
              className={`flex flex-col justify-between rounded-[1.5rem] border-2 border-foreground p-6 shadow-[5px_5px_0_0_var(--foreground)] ${r.color}`}
            >
              <div className="flex gap-0.5">
                {Array.from({ length: 5 }).map((_, i) => (
                  <Star key={i} className="size-4 fill-current" />
                ))}
              </div>
              <blockquote className="mt-4 text-lg font-bold leading-snug">&ldquo;{r.quote}&rdquo;</blockquote>
              <figcaption className="mt-4 text-sm font-black">{r.name}</figcaption>
            </figure>
          ))}
        </div>
      </div>
    </section>
  )
}

import { Check } from "lucide-react"

const PLANS = [
  {
    name: "Taster",
    price: "24",
    blurb: "One case, no strings.",
    points: ["12 cans, one flavor", "Ships in 2–4 days", "Cancel anytime"],
    color: "bg-card",
    featured: false,
  },
  {
    name: "Regular",
    price: "20",
    blurb: "Subscribe & save 15%.",
    points: ["12 cans every month", "Mix any flavors", "Free shipping", "Skip or pause"],
    color: "bg-primary text-primary-foreground",
    featured: true,
  },
  {
    name: "Party",
    price: "40",
    blurb: "Stock up and chill.",
    points: ["24 cans every month", "Mix any flavors", "Free shipping", "Surprise extras"],
    color: "bg-card",
    featured: false,
  },
]

/**
 * Retro pricing — three rounded plan cards; the middle one pops in coral.
 */
export function PricingRetro() {
  return (
    <section className="bg-background px-5 py-16 text-foreground sm:px-8 sm:py-24">
      <div className="mx-auto max-w-6xl">
        <h2 className="text-center text-[clamp(2rem,5vw,3.25rem)] font-black tracking-tight">
          Pick your pace
        </h2>

        <div className="mt-12 grid items-start gap-6 md:grid-cols-3">
          {PLANS.map((p) => (
            <div
              key={p.name}
              className={`flex flex-col rounded-[1.75rem] border-2 border-foreground p-6 shadow-[6px_6px_0_0_var(--foreground)] ${p.color} ${
                p.featured ? "md:-translate-y-3" : ""
              }`}
            >
              <div className="flex items-center justify-between">
                <p className="text-xl font-black">{p.name}</p>
                {p.featured && (
                  <span className="rounded-full border-2 border-foreground bg-accent px-3 py-0.5 text-xs font-black text-foreground">
                    Best value
                  </span>
                )}
              </div>
              <p className={`mt-1.5 font-medium ${p.featured ? "text-primary-foreground/80" : "text-muted-foreground"}`}>
                {p.blurb}
              </p>
              <p className="mt-5 text-5xl font-black tracking-tighter">
                ${p.price}
                <span className="text-base font-bold opacity-70">/case</span>
              </p>
              <ul className="mt-6 flex-1 space-y-2.5">
                {p.points.map((pt) => (
                  <li key={pt} className="flex items-center gap-2.5 font-bold">
                    <span className="grid size-5 place-items-center rounded-full border-2 border-current">
                      <Check className="size-3" />
                    </span>
                    {pt}
                  </li>
                ))}
              </ul>
              <button
                className={`mt-6 rounded-full border-2 border-foreground py-3 font-black shadow-[4px_4px_0_0_var(--foreground)] transition-transform hover:-translate-y-0.5 ${
                  p.featured ? "bg-accent text-foreground" : "bg-primary text-primary-foreground"
                }`}
              >
                Choose {p.name}
              </button>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}
